import{_ as e,o as r,c as t,ag as i}from"./chunks/framework.DXGyWiRo.js";const n=JSON.parse('{"title":"gRPC","description":"","frontmatter":{},"headers":[],"relativePath":"zh/framework/grpc.md","filePath":"zh/framework/grpc.md","lastUpdated":1776812494000}'),s={name:"zh/framework/grpc.md"};function o(c,a,l,d,p,g){return r(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="grpc" tabindex="-1">gRPC <a class="header-anchor" href="#grpc" aria-label="Permalink to &quot;gRPC&quot;">​</a></h1><p>EasyYapi 支持从 gRPC 服务实现导出 API 文档。</p><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>gRPC 支持可以自动识别 gRPC 服务类并提取：</p><ul><li>gRPC 服务路径（<code>/&lt;package&gt;.&lt;ServiceName&gt;/&lt;MethodName&gt;</code>）</li><li>流类型（单向、服务端流、客户端流、双向流）</li><li>请求/响应 protobuf 消息类型</li></ul><h2 id="启用-grpc-支持" tabindex="-1">启用 gRPC 支持 <a class="header-anchor" href="#启用-grpc-支持" aria-label="Permalink to &quot;启用 gRPC 支持&quot;">​</a></h2><p>gRPC 支持默认启用。可以在 IDE 设置中切换：</p><p><kbd>Settings</kbd> &gt; <kbd>Other Settings</kbd> &gt; <kbd>EasyApi</kbd></p><h2 id="类识别" tabindex="-1">类识别 <a class="header-anchor" href="#类识别" aria-label="Permalink to &quot;类识别&quot;">​</a></h2><p>满足以下任一条件的类将被识别为 gRPC 服务：</p><ol><li>继承 <code>io.grpc.BindableService</code>（或生成的 <code>ImplBase</code> 父类）</li><li>标注了 <code>@GrpcService</code> 注解（来自 <a href="https://yidongnan.github.io/grpc-spring-boot-starter/" target="_blank" rel="noreferrer">grpc-spring-boot-starter</a>）</li><li>匹配 <code>class.is.grpc</code> 规则覆盖</li></ol><h3 id="class-is-grpc-规则" tabindex="-1">class.is.grpc 规则 <a class="header-anchor" href="#class-is-grpc-规则" aria-label="Permalink to &quot;class.is.grpc 规则&quot;">​</a></h3><p><code>class.is.grpc</code> 规则可用于自定义 gRPC 服务识别。当此规则对某个类求值为 <code>true</code> 时，该类将被视为 gRPC 服务，而不管默认检测逻辑如何。</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">class.is.grpc</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=groovy:it.isExtend(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;io.grpc.BindableService&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>详见 <a href="/zh/settings/rules/class_is_grpc">class.is.grpc</a>。</p><h2 id="配置" tabindex="-1">配置 <a class="header-anchor" href="#配置" aria-label="Permalink to &quot;配置&quot;">​</a></h2><h3 id="grpc-调用" tabindex="-1">gRPC 调用 <a class="header-anchor" href="#grpc-调用" aria-label="Permalink to &quot;gRPC 调用&quot;">​</a></h3><p>启用 gRPC 调用功能，直接从 IDE 调用 gRPC 方法。此功能在 IDE 设置中配置：</p><p><kbd>Settings</kbd> &gt; <kbd>Other Settings</kbd> &gt; <kbd>EasyApi</kbd> &gt; <kbd>gRPC</kbd></p><p>勾选 <strong>Enable gRPC call</strong> 复选框即可启用 gRPC 调用支持。</p><p>启用 gRPC 调用后，还需要配置 gRPC 运行时依赖。插件需要 gRPC 运行时 JAR 才能调用方法。可以使用 IDE 设置面板中的 <strong>Auto Detect</strong> 按钮自动检测并解析所需依赖。</p><h3 id="grpc-artifact-配置" tabindex="-1">gRPC Artifact 配置 <a class="header-anchor" href="#grpc-artifact-配置" aria-label="Permalink to &quot;gRPC Artifact 配置&quot;">​</a></h3><p>在 IDE 设置中配置 gRPC artifact 坐标用于运行时依赖解析。格式为 <code>groupId:artifactId:version:enabled</code>。</p><h3 id="grpc-额外-jar" tabindex="-1">gRPC 额外 JAR <a class="header-anchor" href="#grpc-额外-jar" aria-label="Permalink to &quot;gRPC 额外 JAR&quot;">​</a></h3><p>在 IDE 设置中添加额外的 JAR 文件用于运行时解析。</p><h3 id="grpc-仓库" tabindex="-1">gRPC 仓库 <a class="header-anchor" href="#grpc-仓库" aria-label="Permalink to &quot;gRPC 仓库&quot;">​</a></h3><p>在 IDE 设置中配置 artifact 仓库用于依赖解析。支持的类型为 <code>maven</code>、<code>gradle</code> 和 <code>custom</code>。</p><h2 id="另见" tabindex="-1">另见 <a class="header-anchor" href="#另见" aria-label="Permalink to &quot;另见&quot;">​</a></h2><ul><li><a href="/zh/guide/export-rpc">导出 RPC 文档</a> — 导出 RPC 文档</li><li><a href="/zh/guide/call#grpc-调用">调用 API</a> — 从 IDE 调用 gRPC 方法</li><li><a href="/zh/settings/ide-setting">IDE 设置</a> — 框架开关设置</li></ul>',29)])])}const b=e(s,[["render",o]]);export{n as __pageData,b as default};
